import React from 'react';
import './App.css';

import Welcome from './apps/welcome/page/welcome/welcome';
import BlogDetail from './apps/blog/page/blogdetail';

function App() {
  let url = new URL(window.location.href);
  let p = url.searchParams.get("p");

  let content = null;
  switch (p) {
    case 'blogDetail' :
        content = (<BlogDetail />);
      break;
    default:
        content = (<Welcome />);
      break;
  }

  return (
    <div className="App">
      <div className="Curtain">
        {content}
      </div>
    </div>
  );
}

export default App;
