import React, { Component } from 'react';
import ReactMarkdown from 'react-markdown';
import './blogdetail.css';
import Navbar from '../component/navbar';

export default class BlogDetail extends Component {
  constructor(props) {
    super(props);
    this.state = {
        content : null
    }

    fetch("/blog/test.md").then((r)=>{this.setState({content:r});});
  }


  render() { 
    let c = this.state.content;
    c = (c !== null)? (<ReactMarkdown source={c} />) : null;
    return (
      <div className="BlogDetail">
        <Navbar items={navbarItems}/>
        <div className="BlogDetail-Content">
            {c}
        </div>
      </div>
    );
  }
}


const navbarItems = [
{value: 'Go To Main', iconClass: 'fa fa-home' },
{value: 'Go To Blog', iconClass: 'fa fa-newspaper-o' },
{value: 'Share', iconClass: 'fa fa-share-alt' },
];
